BlockConfig = {}
BlockConfig.SafeAreas = {}
BlockConfig.MapBlocks = {}

function BlockConfig:initBlockSafeAreas(areas)
    for _, area in pairs(areas) do
        local minX = math.min(tonumber(area.StartPosX), tonumber(area.EndPosX))
        local maxX = math.max(tonumber(area.StartPosX), tonumber(area.EndPosX))
        local minY = math.min(tonumber(area.StartPosY), tonumber(area.EndPosY))
        local maxY = math.max(tonumber(area.StartPosY), tonumber(area.EndPosY))
        local minZ = math.min(tonumber(area.StartPosZ), tonumber(area.EndPosZ))
        local maxZ = math.max(tonumber(area.StartPosZ), tonumber(area.EndPosZ))
        table.insert(self.SafeAreas, {
            minX = minX,
            maxX = maxX,
            minY = minY,
            maxY = maxY,
            minZ = minZ,
            maxZ = maxZ,
        })
    end
end

function BlockConfig:initMapBlocks(blocks)
    for _, block in pairs(blocks) do
        local blockId = tonumber(block.BlockId)
        self.MapBlocks[blockId] = {
            blockId = blockId,
            life = tonumber(block.Life) or 0
        }
    end
end

function BlockConfig:inSafeArea(position)
    for _, area in pairs(self.SafeAreas) do
        if position.x >= area.minX and position.x <= area.maxX and
                position.y >= area.minY and position.y <= area.maxY and
                position.z >= area.minZ and position.z <= area.maxZ then
            return true
        end
    end
    return false
end

function BlockConfig:getBlockLife(blockId)
    local config = self.MapBlocks[blockId]
    if not config then
        return -1
    end
    return config.life
end
